  ('dietitian-moex-02103', 'dietitian', 'dietitian-moex-107-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '針對糖尿病前期（prediabetes）病人，預防罹患糖尿病的照護原則，下列敘述何者錯誤？', '["建議使用sulfonylurea", "建議中強度有氧運動應至少維持150分鐘／星期", "建議每星期可進行2～3次肌力訓練", "建議減少含糖飲料及飽和脂肪之攝取"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:58+00:00", "source_pdf_sha1": "9933f6e8fb40", "answer_pdf_sha1": "99cb4d1e1abb", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
